import unicodedata
def fold_name(s):
    nfc = unicodedata.normalize('NFC', s)
    return nfc.casefold()
print(fold_name('José') == fold_name('JOSE\u0301') or fold_name('José'))
print(fold_name('José'), fold_name('jose'))

def split_nombre(raw):
    parts = ' '.join(raw.strip().split()).split(' ')
    if len(parts) == 1:
        return {'tokens': parts, 'status': 'review', 'raw': raw}
    return {'tokens': parts, 'status': 'ok', 'raw': raw}
print(split_nombre('Luis'))
print(split_nombre('Ana María Pérez'))

policy = {
    '1_token': 'review y conservar raw',
    '2_tokens': 'nombre + apellido_paterno',
    '3_plus': 'nombre(s) + apellidos; no asumir first/last US',
}
for k, v in policy.items():
    print(k, '→', v)

def simple_clean(s):
    # prefer replace/split for literal transforms
    return ' '.join(s.strip().replace(',', ' ').split())
print(simple_clean('  Lima,  Perú '))
print('regex solo si el patrón es no literal')

def jaccard(a, b):
    sa, sb = set(a.lower().split()), set(b.lower().split())
    if not sa and not sb:
        return 1.0
    return len(sa & sb) / len(sa | sb)
print(round(jaccard('Ana Maria', 'Ana María'), 2))
print(round(jaccard('Ana', 'Luis'), 2))

def pipeline(raw):
    import unicodedata
    nfc = unicodedata.normalize('NFC', raw)
    return ' '.join(nfc.strip().split()).casefold()
print(pipeline('  José  '))

metrics = {'pairs_scored': 10, 'auto_link': 2, 'review': 5, 'distinct': 3}
print(metrics)
assert metrics['auto_link'] + metrics['review'] + metrics['distinct'] == metrics['pairs_scored']

report = {
    'method': 'jaccard_tokens + NFC/casefold',
    'threshold_auto': 0.9,
    'threshold_review': 0.6,
    'limitations': 'no prueba parentesco; Unicode forms; 1-token review',
    'privacy': 'solo datos sintéticos',
}
for k, v in report.items():
